import { useEffect, useRef } from 'react';
import { trapFocus } from '../a11y/trap-focus';
import './whatsnew.css';

interface Props { onClose: () => void; }

const ITEMS: ReadonlyArray<{ tag: string; body: string }> = [
  { tag: 'One-tap start', body: 'Brand-new players land on a single big "Play your first puzzle" button.' },
  { tag: 'Friendlier first puzzles', body: 'No timer, no mistake counter, free hints, and gentle nudges if you get stuck.' },
  { tag: 'Plain language', body: 'No jargon in the main UI — terms like "nonogram" live in the Help center now.' },
  { tag: 'Smooth transitions', body: 'Subtle fades between screens, with reduced-motion respected.' },
  { tag: 'Progressive disclosure', body: 'Power-user options (hard mode, custom puzzles) live behind a Settings toggle until you win 5 puzzles.' },
  { tag: 'Empty-state polish', body: 'Stats and achievement screens now invite you in before you have a streak.' },
  { tag: 'Loading skeletons', body: 'Every spinner is now a soft placeholder that matches the layout.' },
];

/**
 * Lazy-loaded "what's new in v0.4.0" popover. Surfaces the headline changes
 * from CHANGELOG.md in a compact list. Self-closing once dismissed (persists).
 */
export function WhatsNewSheet({ onClose }: Props) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  return (
    <div className="etch-wn-backdrop" role="dialog" aria-modal="true" aria-label="What's new" onClick={onClose}>
      <div className="etch-wn-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <span className="etch-wn-eyebrow">v0.5.0</span>
          <h2>What's new</h2>
          <button className="etch-wn-close" aria-label="Close" onClick={onClose}>×</button>
        </header>
        <ul className="etch-wn-list">
          {ITEMS.map((it) => (
            <li key={it.tag}>
              <strong>{it.tag}.</strong> {it.body}
            </li>
          ))}
        </ul>
        <footer>
          <button type="button" className="etch-wn-ok" onClick={onClose}>Got it</button>
        </footer>
      </div>
    </div>
  );
}

export default WhatsNewSheet;
